import{_ as t,c as i,o as n,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Superpowers Agent Reference: Complete Guide to code-reviewer Triggers and Six Review Dimensions","description":"Learn the complete reference for Superpowers agent system. This guide details code-reviewer agent triggers, six review dimensions (plan alignment analysis, code quality assessment, architecture design review, documentation and standards check, issue identification recommendations, communication protocol) and best practices. Master how to efficiently use code review agent to improve project quality and development efficiency, ensuring code complies with design specifications and best practices.","frontmatter":{"title":"Superpowers Agent Reference: Complete Guide to code-reviewer Triggers and Six Review Dimensions","sidebarTitle":"Agent Reference","subtitle":"Agent Reference","description":"Learn the complete reference for Superpowers agent system. This guide details code-reviewer agent triggers, six review dimensions (plan alignment analysis, code quality assessment, architecture design review, documentation and standards check, issue identification recommendations, communication protocol) and best practices. Master how to efficiently use code review agent to improve project quality and development efficiency, ensuring code complies with design specifications and best practices.","tags":["Reference","Agents","Code Review"],"prerequisite":["start-using-skills"],"order":280},"headers":[],"relativePath":"obra/superpowers/appendix/agents-reference/index.md","filePath":"obra/superpowers/appendix/agents-reference/index.md"}'),s={name:"obra/superpowers/appendix/agents-reference/index.md"};function r(o,e,d,l,c,p){return n(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="agent-reference" tabindex="-1">Agent Reference <a class="header-anchor" href="#agent-reference" aria-label="Permalink to &quot;Agent Reference&quot;">​</a></h1><p>Superpowers provides specialized AI capabilities for specific tasks through the agent system. Each agent has clear trigger conditions, review standards, and workflows.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Differences between agents and skills:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Skills</th><th>Agents</th></tr></thead><tbody><tr><td>Definition</td><td>Markdown file (SKILL.md)</td><td>Agent definition file (.md)</td></tr><tr><td>Invocation</td><td>Loaded via Skill tool</td><td>Via @mention or skill call</td></tr><tr><td>Use Case</td><td>General workflows and best practices</td><td>Specialized execution for specific tasks</td></tr><tr><td>Count</td><td>14</td><td>1 (code-reviewer)</td></tr></tbody></table><h2 id="code-reviewer-agent" tabindex="-1">code-reviewer Agent <a class="header-anchor" href="#code-reviewer-agent" aria-label="Permalink to &quot;code-reviewer Agent&quot;">​</a></h2><h3 id="basic-information" tabindex="-1">Basic Information <a class="header-anchor" href="#basic-information" aria-label="Permalink to &quot;Basic Information&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Content</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>code-reviewer</td></tr><tr><td><strong>Type</strong></td><td>Senior Code Reviewer</td></tr><tr><td><strong>Domain</strong></td><td>Code review, architecture review, quality assurance</td></tr><tr><td><strong>Model</strong></td><td>inherit (inherits current session model)</td></tr><tr><td><strong>Definition File</strong></td><td><code>agents/code-reviewer.md</code></td></tr></tbody></table><h3 id="trigger-conditions" tabindex="-1">Trigger Conditions <a class="header-anchor" href="#trigger-conditions" aria-label="Permalink to &quot;Trigger Conditions&quot;">​</a></h3><p>The code-reviewer agent should be invoked when any of the following conditions are met:</p><ol><li><strong>Major project step completed</strong>: Logic code blocks are written and need verification against the original plan</li><li><strong>Feature implementation completed</strong>: Important feature implementation is finished and needs review against architecture or planning documents</li><li><strong>Plan step completed</strong>: A numbered step in the planning document has been completed</li></ol><div class="info custom-block"><p class="custom-block-title">Example Scenarios</p><p><strong>Scenario 1</strong>: User completes a major system module</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>&quot;I&#39;ve finished implementing the user authentication system as outlined in step 3 of our plan&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI response:</span></span>
<span class="line"><span>&quot;Great work! Now let me use the code-reviewer agent to review the implementation against our plan and coding standards&quot;</span></span></code></pre></div><p><strong>Scenario 2</strong>: User completes a feature module</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>&quot;The API endpoints for the task management system are now complete - that covers step 2 from our architecture document&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI response:</span></span>
<span class="line"><span>&quot;Excellent! Let me have the code-reviewer agent examine this implementation to ensure it aligns with our plan and follows best practices&quot;</span></span></code></pre></div></div><h3 id="review-dimensions" tabindex="-1">Review Dimensions <a class="header-anchor" href="#review-dimensions" aria-label="Permalink to &quot;Review Dimensions&quot;">​</a></h3><p>The code-reviewer agent reviews from the following six dimensions:</p><h4 id="_1-plan-alignment-analysis" tabindex="-1">1. Plan Alignment Analysis <a class="header-anchor" href="#_1-plan-alignment-analysis" aria-label="Permalink to &quot;1. Plan Alignment Analysis&quot;">​</a></h4><ul><li>✅ Compare implementation against original planning document or step descriptions</li><li>✅ Identify implementation approaches, architectures, or requirements that deviate from the plan</li><li>✅ Evaluate whether deviations are reasonable improvements or harmful deviations</li><li>✅ Verify all planned features are implemented</li></ul><h4 id="_2-code-quality-assessment" tabindex="-1">2. Code Quality Assessment <a class="header-anchor" href="#_2-code-quality-assessment" aria-label="Permalink to &quot;2. Code Quality Assessment&quot;">​</a></h4><ul><li>✅ Review code for adherence to established patterns and conventions</li><li>✅ Check error handling, type safety, and defensive programming</li><li>✅ Evaluate code organization, naming conventions, and maintainability</li><li>✅ Assess test coverage and test implementation quality</li><li>✅ Identify potential security vulnerabilities or performance issues</li></ul><h4 id="_3-architecture-and-design-review" tabindex="-1">3. Architecture and Design Review <a class="header-anchor" href="#_3-architecture-and-design-review" aria-label="Permalink to &quot;3. Architecture and Design Review&quot;">​</a></h4><ul><li>✅ Ensure implementation follows SOLID principles and established architecture patterns</li><li>✅ Check for separation of concerns and loose coupling</li><li>✅ Verify integration with existing systems</li><li>✅ Evaluate scalability and extensibility considerations</li></ul><h4 id="_4-documentation-and-standards" tabindex="-1">4. Documentation and Standards <a class="header-anchor" href="#_4-documentation-and-standards" aria-label="Permalink to &quot;4. Documentation and Standards&quot;">​</a></h4><ul><li>✅ Verify code includes appropriate comments and documentation</li><li>✅ Check that file headers, function documentation, and inline comments exist and are accurate</li><li>✅ Ensure project-specific coding standards and conventions are followed</li></ul><h4 id="_5-issue-identification-and-recommendations" tabindex="-1">5. Issue Identification and Recommendations <a class="header-anchor" href="#_5-issue-identification-and-recommendations" aria-label="Permalink to &quot;5. Issue Identification and Recommendations&quot;">​</a></h4><ul><li>✅ Clearly categorize issues as: Critical (must fix), Important (should fix), or Suggestions (recommend improvements)</li><li>✅ Provide specific examples and actionable suggestions for each issue</li><li>✅ When identifying plan deviations, explain whether they are harmful or beneficial</li><li>✅ Propose specific improvement suggestions, with code examples when helpful</li></ul><h4 id="_6-communication-protocol" tabindex="-1">6. Communication Protocol <a class="header-anchor" href="#_6-communication-protocol" aria-label="Permalink to &quot;6. Communication Protocol&quot;">​</a></h4><ul><li>✅ If significant deviations from the plan are found, require the coding agent to review and confirm changes</li><li>✅ If issues with the original plan itself are found, suggest updating the plan</li><li>✅ Provide clear fix guidance for implementation issues</li><li>✅ Always acknowledge what was done well before highlighting issues</li></ul><h3 id="output-format-requirements" tabindex="-1">Output Format Requirements <a class="header-anchor" href="#output-format-requirements" aria-label="Permalink to &quot;Output Format Requirements&quot;">​</a></h3><p>The code-reviewer agent output should:</p><ol><li><strong>Structured</strong>: Clearly organized by issue category</li><li><strong>Actionable</strong>: Each issue has specific suggestions and examples</li><li><strong>Constructive</strong>: Points out problems while also acknowledging strengths</li><li><strong>Concise</strong>: Comprehensive but not verbose</li><li><strong>Helpful</strong>: Helps improve current implementation and future development practices</li></ol><h3 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Usage Recommendations</p><ol><li><strong>Invoke promptly</strong>: Call immediately after completing major steps to prevent issues from accumulating</li><li><strong>Provide specific feedback</strong>: Avoid vague evaluations; provide code line numbers and examples</li><li><strong>Balance feedback</strong>: Both point out problems and acknowledge strengths</li><li><strong>Actionable suggestions</strong>: Every suggestion should be directly convertible to action</li><li><strong>Respect the plan</strong>: When deviating from the plan, explain reasons and impact</li></ol></div><h2 id="future-extensions" tabindex="-1">Future Extensions <a class="header-anchor" href="#future-extensions" aria-label="Permalink to &quot;Future Extensions&quot;">​</a></h2><p>Currently Superpowers only includes the code-reviewer agent. Potential agent types that may be added in the future:</p><table tabindex="0"><thead><tr><th>Agent Type</th><th>Potential Use</th></tr></thead><tbody><tr><td>test-writer</td><td>Agent specialized in generating test cases</td></tr><tr><td>debugger</td><td>Agent focused on systematic debugging</td></tr><tr><td>security-auditor</td><td>Dedicated security audit agent</td></tr><tr><td>performance-optimizer</td><td>Performance optimization specialist agent</td></tr><tr><td>documentation-writer</td><td>Agent for documentation generation and maintenance</td></tr></tbody></table><h2 id="related-skills" tabindex="-1">Related Skills <a class="header-anchor" href="#related-skills" aria-label="Permalink to &quot;Related Skills&quot;">​</a></h2><p>The agent system works in conjunction with the following skills:</p><table tabindex="0"><thead><tr><th>Skill Name</th><th>Relationship with Agents</th></tr></thead><tbody><tr><td>requesting-code-review</td><td>Invokes code-reviewer agent</td></tr><tr><td>receiving-code-review</td><td>Receives agent review feedback</td></tr><tr><td>subagent-driven-development</td><td>Uses agents in subagent development</td></tr></tbody></table><h2 id="appendix-agent-definition-file-structure" tabindex="-1">Appendix: Agent Definition File Structure <a class="header-anchor" href="#appendix-agent-definition-file-structure" aria-label="Permalink to &quot;Appendix: Agent Definition File Structure&quot;">​</a></h2><p>Agent definition files use YAML frontmatter to configure basic properties:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;agent name&gt;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  Detailed description of the agent, including trigger conditions and usage examples</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">inherit | &lt;model name&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Detailed role definition and workflow for the agent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>Field Descriptions</strong>:</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>name</td><td>string</td><td>Y</td><td>Agent unique identifier (kebab-case)</td></tr><tr><td>description</td><td>string</td><td>Y</td><td>Description of agent purpose and trigger conditions</td></tr><tr><td>model</td><td>string</td><td>N</td><td>Model to use, inherit means inheriting current session model</td></tr></tbody></table><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>code-reviewer agent definition</td><td><a href="https://github.com/obra/superpowers/blob/main/agents/code-reviewer.md" target="_blank" rel="noreferrer"><code>agents/code-reviewer.md</code></a></td><td>1-49</td></tr></tbody></table><p><strong>Key Configuration</strong>:</p><ul><li><code>name: code-reviewer</code>: Agent unique identifier</li><li><code>model: inherit</code>: Inherits current session model</li><li><code>description</code>: Includes trigger conditions and usage examples</li></ul><p><strong>Review Dimensions</strong>:</p><ul><li>Plan Alignment Analysis</li><li>Code Quality Assessment</li><li>Architecture and Design Review</li><li>Documentation and Standards</li><li>Issue Identification and Recommendations</li><li>Communication Protocol</li></ul></details>`,45)])])}const g=t(s,[["render",r]]);export{u as __pageData,g as default};
